import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';

export default function AdminFees() {
  const [fees, setFees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('');
  const [showReceipt, setShowReceipt] = useState(null);

  useEffect(() => {
    axios.get('/fees').then(r => setFees(r.data)).catch(console.error).finally(() => setLoading(false));
  }, []);

  const handleCollect = async (id) => {
    if (!window.confirm('Mark this fee as collected?')) return;
    try {
      const r = await axios.put(`/fees/${id}/collect`, { paymentMode: 'cash' });
      setFees(fees.map(f => f.id === id ? r.data.fee : f));
      setShowReceipt(r.data.fee);
    } catch (err) {
      alert(err.response?.data?.message || 'Failed to collect payment');
    }
  };

  const filtered = fees.filter(f => 
    f.Student?.user?.name?.toLowerCase().includes(filter.toLowerCase()) ||
    f.Student?.studentId?.toLowerCase().includes(filter.toLowerCase())
  );

  const fmt = n => `₹${Number(n).toLocaleString('en-IN')}`;

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="animate-fade">
      <div className="page-hero">
        <p className="page-hero-label">Administrative Finance</p>
        <h2>Fee Records</h2>
        <p className="page-hero-meta">Track and manage student transportation payments</p>
      </div>

      <div className="card" style={{ marginBottom: 24 }}>
        <div className="card-header">
          <h3 className="card-title"><span>🔍</span> Transaction Search</h3>
        </div>
        <div style={{ padding: 24 }}>
          <input 
            className="input-field" 
            placeholder="Search by student name or ID..." 
            value={filter}
            onChange={e => setFilter(e.target.value)}
          />
        </div>
      </div>

      <div className="card">
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Student</th>
                <th>Period</th>
                <th>Amount</th>
                <th>Due Date</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(f => (
                <tr key={f.id}>
                  <td>
                    <div>
                      <div style={{ fontWeight: 700 }}>{f.Student?.user?.name}</div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{f.Student?.studentId}</div>
                    </div>
                  </td>
                  <td><strong>{f.feePeriod}</strong></td>
                  <td>{fmt(f.totalAmount)}</td>
                  <td className="text-muted">{f.dueDate}</td>
                  <td><span className={`badge badge-${f.status}`}>{f.status}</span></td>
                  <td>
                    {f.status !== 'paid' ? (
                      <button className="btn btn-primary" style={{ padding: '6px 12px', fontSize: 12, width: 'auto' }} onClick={() => handleCollect(f.id)}>
                        Collect Cash
                      </button>
                    ) : (
                      <button className="btn btn-secondary" style={{ padding: '6px 12px', fontSize: 12, width: 'auto' }} onClick={() => setShowReceipt(f)}>
                        View Receipt
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showReceipt && (
        <div className="modal-overlay">
          <div className="modal-content animate-slide" style={{ maxWidth: 500 }}>
            <div className="receipt-container" style={{ padding: 40, background: 'white' }}>
              <div style={{ textAlign: 'center', marginBottom: 30 }}>
                <img src="/assets/logo.png" alt="KEC" style={{ height: 60, marginBottom: 12 }} />
                <h2 style={{ fontSize: 18, color: 'var(--primary)' }}>Kongu Engineering College</h2>
                <p style={{ fontSize: 11, color: 'var(--text-muted)' }}>Perundurai, Erode - 638060</p>
                <div style={{ margin: '20px 0', borderTop: '1px dashed var(--border)', borderBottom: '1px dashed var(--border)', padding: '10px 0' }}>
                  <h3 style={{ fontSize: 14, textTransform: 'uppercase', letterSpacing: 2 }}>Payment Receipt</h3>
                </div>
              </div>
              <div className="info-list" style={{ border: 'none' }}>
                <div className="info-row" style={{ padding: '8px 0' }}><span>Receipt No</span><strong>#KEC-{showReceipt.id}</strong></div>
                <div className="info-row" style={{ padding: '8px 0' }}><span>Date</span><strong>{new Date().toLocaleDateString()}</strong></div>
                <div className="info-row" style={{ padding: '8px 0' }}><span>Student</span><strong>{showReceipt.Student?.user?.name}</strong></div>
                <div className="info-row" style={{ padding: '8px 0' }}><span>ID</span><strong>{showReceipt.Student?.studentId}</strong></div>
                <div className="info-row" style={{ padding: '8px 0' }}><span>Fee Period</span><strong>{showReceipt.feePeriod}</strong></div>
                <div className="info-row" style={{ padding: '20px 0 10px', borderTop: '1px solid var(--border)' }}>
                  <span>Amount Paid</span>
                  <strong style={{ fontSize: 20, color: 'var(--success)' }}>{fmt(showReceipt.totalAmount)}</strong>
                </div>
              </div>
              <div style={{ textAlign: 'center', marginTop: 40 }}>
                <p style={{ fontSize: 11, color: 'var(--text-muted)', fontStyle: 'italic' }}>Computer generated receipt. No signature required.</p>
                <button className="btn btn-primary" style={{ marginTop: 24 }} onClick={() => setShowReceipt(null)}>Close</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
